use crate::types::{DecideInput, DecideOutput};

const PI: f64 = 3.1415926535;

fn realcompare(a: f64, b: f64) -> &'static str {
    // Compare with respect to six most significant digits:
    // normalize both numbers to signed 6‑digit integers and compare.
    fn to_six_sig(x: f64) -> i64 {
        if x == 0.0 {
            return 0;
        }
        let sign = if x < 0.0 { -1 } else { 1 };
        let ax = x.abs();
        let log10 = ax.log10();
        if !log10.is_finite() {
            return (sign as i64) * ax.round() as i64;
        }
        let exp = log10.floor() as i32;
        let mut scale_exp = 5 - exp;
        if scale_exp > 308 {
            scale_exp = 308;
        } else if scale_exp < -308 {
            scale_exp = -308;
        }
        let scale = 10f64.powi(scale_exp);
        let scaled = ax * scale;
        let rounded = scaled.round();
        (sign as i64) * rounded as i64
    }

    let na = to_six_sig(a);
    let nb = to_six_sig(b);
    if na < nb {
        "LT"
    } else if na > nb {
        "GT"
    } else {
        "EQ"
    }
}

fn gt(a: f64, b: f64) -> bool {
    realcompare(a, b) == "GT"
}

fn lt(a: f64, b: f64) -> bool {
    realcompare(a, b) == "LT"
}

fn eq(a: f64, b: f64) -> bool {
    realcompare(a, b) == "EQ"
}

fn distance(x1: f64, y1: f64, x2: f64, y2: f64) -> f64 {
    let dx = x2 - x1;
    let dy = y2 - y1;
    (dx * dx + dy * dy).sqrt()
}

fn triangle_area(
    x1: f64,
    y1: f64,
    x2: f64,
    y2: f64,
    x3: f64,
    y3: f64,
) -> f64 {
    let area2 = x1 * (y2 - y3) + x2 * (y3 - y1) + x3 * (y1 - y2);
    0.5 * area2.abs()
}

fn minimal_enclosing_circle_radius_for_three(
    x1: f64,
    y1: f64,
    x2: f64,
    y2: f64,
    x3: f64,
    y3: f64,
) -> f64 {
    let a = distance(x2, y2, x3, y3);
    let b = distance(x1, y1, x3, y3);
    let c = distance(x1, y1, x2, y2);
    let max_side = a.max(b).max(c);

    // Twice the area (parallelogram area) via cross product
    let cross = (x2 - x1) * (y3 - y1) - (y2 - y1) * (x3 - x1);
    if eq(cross, 0.0) {
        // Collinear: minimal circle has diameter equal to longest side
        return 0.5 * max_side;
    }

    let area = 0.5 * cross.abs();
    // Circumradius formula: R = a*b*c / (4*A)
    let denom = 4.0 * area;
    if eq(denom, 0.0) {
        0.5 * max_side
    } else {
        (a * b * c) / denom
    }
}

fn angle_between(
    vx1: f64,
    vy1: f64,
    vx2: f64,
    vy2: f64,
) -> Option<f64> {
    let len1 = (vx1 * vx1 + vy1 * vy1).sqrt();
    let len2 = (vx2 * vx2 + vy2 * vy2).sqrt();
    if eq(len1, 0.0) || eq(len2, 0.0) {
        return None;
    }
    let dot = vx1 * vx2 + vy1 * vy2;
    let cos_theta = (dot / (len1 * len2)).clamp(-1.0, 1.0);
    Some(cos_theta.acos())
}

fn same_point(
    x1: f64,
    y1: f64,
    x2: f64,
    y2: f64,
) -> bool {
    eq(x1, x2) && eq(y1, y2)
}

fn quadrant(x: f64, y: f64) -> u8 {
    if x >= 0.0 && y >= 0.0 {
        1
    } else if x < 0.0 && y >= 0.0 {
        2
    } else if x <= 0.0 && y < 0.0 {
        3
    } else {
        4
    }
}

fn lic1(input: &DecideInput) -> bool {
    let n = input.numpoints;
    if n < 2 {
        return false;
    }
    let length1 = input.parameters.length1;
    for i in 0..(n - 1) {
        let d = distance(
            input.x[i],
            input.y[i],
            input.x[i + 1],
            input.y[i + 1],
        );
        if gt(d, length1) {
            return true;
        }
    }
    false
}

fn lic2(input: &DecideInput) -> bool {
    let n = input.numpoints;
    if n < 3 {
        return false;
    }
    let r = input.parameters.radius1;
    for i in 0..(n - 2) {
        let x1 = input.x[i];
        let y1 = input.y[i];
        let x2 = input.x[i + 1];
        let y2 = input.y[i + 1];
        let x3 = input.x[i + 2];
        let y3 = input.y[i + 2];
        let rad = minimal_enclosing_circle_radius_for_three(x1, y1, x2, y2, x3, y3);
        if gt(rad, r) {
            return true;
        }
    }
    false
}

fn lic3(input: &DecideInput) -> bool {
    let n = input.numpoints;
    if n < 3 {
        return false;
    }
    let epsilon = input.parameters.epsilon;
    for i in 0..(n - 2) {
        let x1 = input.x[i];
        let y1 = input.y[i];
        let xv = input.x[i + 1];
        let yv = input.y[i + 1];
        let x3 = input.x[i + 2];
        let y3 = input.y[i + 2];

        if same_point(x1, y1, xv, yv) || same_point(x3, y3, xv, yv) {
            continue;
        }

        let vx1 = x1 - xv;
        let vy1 = y1 - yv;
        let vx2 = x3 - xv;
        let vy2 = y3 - yv;

        if let Some(angle) = angle_between(vx1, vy1, vx2, vy2) {
            if lt(angle, PI - epsilon) || gt(angle, PI + epsilon) {
                return true;
            }
        }
    }
    false
}

fn lic4(input: &DecideInput) -> bool {
    let n = input.numpoints;
    if n < 3 {
        return false;
    }
    let area1 = input.parameters.area1;
    for i in 0..(n - 2) {
        let a = triangle_area(
            input.x[i],
            input.y[i],
            input.x[i + 1],
            input.y[i + 1],
            input.x[i + 2],
            input.y[i + 2],
        );
        if gt(a, area1) {
            return true;
        }
    }
    false
}

fn lic5(input: &DecideInput) -> bool {
    let n = input.numpoints;
    let q_pts = input.parameters.q_pts;
    if q_pts < 2 || q_pts > n {
        return false;
    }
    let quads_limit = input.parameters.quads as usize;
    for start in 0..=(n - q_pts) {
        let mut seen = [false; 4];
        for i in start..(start + q_pts) {
            let q = quadrant(input.x[i], input.y[i]);
            seen[(q - 1) as usize] = true;
        }
        let mut count = 0;
        for s in &seen {
            if *s {
                count += 1;
            }
        }
        if count > quads_limit {
            return true;
        }
    }
    false
}

fn lic6(input: &DecideInput) -> bool {
    let n = input.numpoints;
    if n < 2 {
        return false;
    }
    for i in 0..(n - 1) {
        if lt(input.x[i + 1], input.x[i]) {
            return true;
        }
    }
    false
}

fn lic7(input: &DecideInput) -> bool {
    let n = input.numpoints;
    if n < 3 {
        return false;
    }
    let n_pts = input.parameters.n_pts;
    if n_pts < 3 || n_pts > n {
        return false;
    }
    let dist_limit = input.parameters.dist;
    for start in 0..=(n - n_pts) {
        let end = start + n_pts - 1;
        let x1 = input.x[start];
        let y1 = input.y[start];
        let x2 = input.x[end];
        let y2 = input.y[end];
        let mut exceeded = false;
        if same_point(x1, y1, x2, y2) {
            for k in start..=end {
                if k == start {
                    continue;
                }
                let d = distance(x1, y1, input.x[k], input.y[k]);
                if gt(d, dist_limit) {
                    exceeded = true;
                    break;
                }
            }
        } else {
            let dx = x2 - x1;
            let dy = y2 - y1;
            let denom = (dx * dx + dy * dy).sqrt();
            if !eq(denom, 0.0) {
                for k in start + 1..end {
                    let num = (dx * (input.y[k] - y1) - dy * (input.x[k] - x1)).abs();
                    let d = num / denom;
                    if gt(d, dist_limit) {
                        exceeded = true;
                        break;
                    }
                }
            }
        }
        if exceeded {
            return true;
        }
    }
    false
}

fn lic8(input: &DecideInput) -> bool {
    let n = input.numpoints;
    if n < 3 {
        return false;
    }
    let k_pts = input.parameters.k_pts;
    if k_pts < 1 || k_pts > n - 2 {
        return false;
    }
    let length1 = input.parameters.length1;
    for i in 0..=(n - k_pts - 2) {
        let j = i + k_pts + 1;
        let d = distance(input.x[i], input.y[i], input.x[j], input.y[j]);
        if gt(d, length1) {
            return true;
        }
    }
    false
}

fn lic9(input: &DecideInput) -> bool {
