    let b_pts = input.parameters.b_pts;
    if a_pts < 1 || b_pts < 1 {
        return false;
    }
    if a_pts + b_pts > n - 3 {
        return false;
    }
    let r1 = input.parameters.radius1;
    for i in 0..=(n - a_pts - b_pts - 3) {
        let j = i + a_pts + 1;
        let k = j + b_pts + 1;
        let x1 = input.x[i];
        let y1 = input.y[i];
        let x2 = input.x[j];
        let y2 = input.y[j];
        let x3 = input.x[k];
        let y3 = input.y[k];
        let rad = minimal_enclosing_circle_radius_for_three(x1, y1, x2, y2, x3, y3);
        if gt(rad, r1) {
            return true;
        }
    }
    false
}

