fn lic13(input: &DecideInput) -> bool {
    let n = input.numpoints;
    if n < 3 {
        return false;
    }
    let k_pts = input.parameters.k_pts;
    if k_pts < 1 || k_pts > n - 2 {
        return false;
    }
    let length1 = input.parameters.length1;
    let length2 = input.parameters.length2;
    let mut exists_gt = false;
    let mut exists_lt = false;
    for i in 0..=(n - k_pts - 2) {
        let j = i + k_pts + 1;
        let d = distance(input.x[i], input.y[i], input.x[j], input.y[j]);
        if gt(d, length1) {
            exists_gt = true;
        }
        if lt(d, length2) {
            exists_lt = true;
        }
        if exists_gt && exists_lt {
            return true;
        }
    }
    false
}

