    }
    let r1 = input.parameters.radius1;
    let r2 = input.parameters.radius2;
    let mut exists_gt = false;
    let mut exists_le = false;
    for i in 0..=(n - a_pts - b_pts - 3) {
        let j = i + a_pts + 1;
        let k = j + b_pts + 1;
        let x1 = input.x[i];
        let y1 = input.y[i];
        let x2 = input.x[j];
        let y2 = input.y[j];
        let x3 = input.x[k];
        let y3 = input.y[k];
        let rad = minimal_enclosing_circle_radius_for_three(x1, y1, x2, y2, x3, y3);
        if gt(rad, r1) {
            exists_gt = true;
        }
        if !gt(rad, r2) {
            exists_le = true;
        }
        if exists_gt && exists_le {
            return true;
        }
    }
    false
}

