pub fn decide(input: &DecideInput) -> DecideOutput {
    let mut cmv = vec![false; 15];
    cmv[0] = lic1(input);
    cmv[1] = lic2(input);
    cmv[2] = lic3(input);
    cmv[3] = lic4(input);
    cmv[4] = lic5(input);
    cmv[5] = lic6(input);
    cmv[6] = lic7(input);
    cmv[7] = lic8(input);
    cmv[8] = lic9(input);
    cmv[9] = lic10(input);
    cmv[10] = lic11(input);
    cmv[11] = lic12(input);
    cmv[12] = lic13(input);
    cmv[13] = lic14(input);
    cmv[14] = lic15(input);

    let mut pum = vec![vec![true; 15]; 15];
    for i in 0..15 {
        for j in 0..15 {
            if i == j {
                pum[i][j] = input.pum_diag[i];
            } else {
                let conn = &input.lcm[i][j];
                pum[i][j] = match conn.as_str() {
                    "NOTUSED" => true,
                    "ANDD" => cmv[i] && cmv[j],
                    "ORR" => cmv[i] || cmv[j],
                    _ => true,
                };
            }
        }
    }

    let mut fuv = vec![false; 15];
    for i in 0..15 {
        if !pum[i][i] {
            fuv[i] = true;
        } else {
            let mut all_true = true;
            for j in 0..15 {
                if !pum[i][j] {
                    all_true = false;
                    break;
                }
            }
            fuv[i] = all_true;
        }
    }

    let launch = fuv.iter().all(|&b| b);

    DecideOutput {
        cmv,
        pum,
        fuv,
        launch,
    }
}
